import org.jsoup.Jsoup;
import org.jsoup.nodes.Document;
import java.io.File;

public class debug_test {
    public static void main(String[] args) throws Exception {
        File in = new File("src/test/resources/htmltests/table-invalid-elements.html");
        Document doc = Jsoup.parse(in, "UTF-8");
        doc.outputSettings().prettyPrint(true);
        String rendered = doc.toString();
        System.out.println("Rendered HTML:");
        System.out.println(rendered);
        System.out.println("\n");

        int endOfEmail = rendered.indexOf("Comment");
        int guarantee = rendered.indexOf("Why am I here?");
        System.out.println("Position of 'Comment': " + endOfEmail);
        System.out.println("Position of 'Why am I here?': " + guarantee);
        System.out.println("Comment found: " + (endOfEmail > -1));
        System.out.println("Search text found: " + (guarantee > -1));
        System.out.println("Search text after comment: " + (guarantee > endOfEmail));
    }
}

